689	func pluginRootCandidates(workingDir string, name string, entry registry.InstalledEntry) []string {
690		var roots []string
691		if workingDir != "" {
692			roots = append(roots, filepath.Join(workingDir, ".ddx", "plugins", name))
693		}
694		roots = append(roots, registry.ExpandHome(filepath.Join("~", ".ddx", "plugins", name)))
695		for _, f := range entry.Files {
696			expanded := registry.ExpandHome(f)
697			if expanded == "" {
698				continue
699			}
700			roots = append(roots, pluginRootFromRecordedFile(expanded, name))
701		}
702		return uniqueStrings(roots)
703	}
