705	func pluginRootFromRecordedFile(path string, name string) string {
706		cleaned := filepath.Clean(path)
707		if filepath.Base(cleaned) == name {
708			return cleaned
709		}
710		for dir := cleaned; dir != "." && dir != string(filepath.Separator); dir = filepath.Dir(dir) {
711			if filepath.Base(dir) == name && filepath.Base(filepath.Dir(dir)) == "plugins" {
712				return dir
713			}
714			next := filepath.Dir(dir)
715			if next == dir {
716				break
717			}
718		}
719		return cleaned
720	}
